"use client";

import { useEffect, useState } from "react";
import { BearBackground } from "@/components/ui/bear-background";
import { FloatingHearts } from "@/components/ui/floating-hearts";
import { FloatingStatCards } from "@/components/ui/floating-stat-cards";
import { LanguageSwitch } from "@/components/ui/language-switch";
import { MusicDock } from "@/components/ui/music-dock";
import { Reveal } from "@/components/ui/reveal";
import { BabySection } from "@/features/invitation/sections/baby-section";
import { HeroSection } from "@/features/invitation/sections/hero-section";
import { ParentsSection } from "@/features/invitation/sections/parents-section";
import { PhotosSection } from "@/features/invitation/sections/photos-section";
import { PhraseSection } from "@/features/invitation/sections/phrase-section";
import { RSVPSection } from "@/features/invitation/sections/rsvp-section";
import { invitationContent, type Locale } from "@/data/invitation";

export function InvitationPage() {
  const [locale, setLocale] = useState<Locale>("es");
  const content = invitationContent[locale];

  useEffect(() => {
    document.documentElement.lang = locale;
  }, [locale]);

  return (
    <main className="relative min-h-screen overflow-hidden bg-[linear-gradient(180deg,#eff8ff_0%,#f8fbff_45%,#ffffff_100%)] text-slate-900">
      <BearBackground />
      <FloatingHearts />
      <div className="fixed right-4 top-4 z-50 sm:right-6 sm:top-6">
        <LanguageSwitch
          locale={locale}
          onToggle={() => setLocale((current) => (current === "es" ? "en" : "es"))}
          label={locale === "es" ? "Cambiar idioma a inglés" : "Switch language to Spanish"}
        />
      </div>
      <MusicDock title={content.music.title} description={content.music.description} />
      <div className="relative mx-auto flex w-full max-w-7xl flex-col gap-8 px-4 py-6 sm:px-6 lg:px-8 lg:py-10">
        <Reveal className="relative">
          <FloatingStatCards locale={locale} />
          <HeroSection locale={locale} />
        </Reveal>
        <section className="grid gap-8 lg:grid-cols-2">
          <Reveal delayClassName="reveal-delay-1">
            <PhraseSection locale={locale} />
          </Reveal>
          <Reveal delayClassName="reveal-delay-2">
            <ParentsSection locale={locale} />
          </Reveal>
        </section>
        <Reveal delayClassName="reveal-delay-1">
          <BabySection locale={locale} />
        </Reveal>
        <Reveal delayClassName="reveal-delay-2">
          <PhotosSection locale={locale} />
        </Reveal>
        <Reveal delayClassName="reveal-delay-3">
          <RSVPSection locale={locale} />
        </Reveal>
      </div>
    </main>
  );
}
