"use client";

import { Music2, Pause, Play } from "lucide-react";
import { useBackgroundMusic } from "@/hooks/use-background-music";

interface MusicDockProps {
  title: string;
  description: string;
}

export function MusicDock({ title, description }: MusicDockProps) {
  const { isPlaying, play, stop } = useBackgroundMusic();

  return (
    <div className="fixed bottom-4 right-4 z-50 max-w-[calc(100vw-2rem)] sm:bottom-6 sm:right-6">
      <div className="flex items-center gap-3 rounded-full border border-white/70 bg-white/90 px-4 py-3 shadow-[0_20px_60px_rgba(59,130,246,0.18)] backdrop-blur-xl">
        <span className="flex h-10 w-10 items-center justify-center rounded-full bg-sky-100 text-sky-700">
          <Music2 className="h-5 w-5" />
        </span>
        <div className="hidden sm:block">
          <p className="text-xs font-semibold uppercase tracking-[0.3em] text-sky-700">{title}</p>
          <p className="text-sm text-slate-600">{description}</p>
        </div>
        <button
          type="button"
          onClick={isPlaying ? stop : play}
          className="inline-flex h-11 w-11 items-center justify-center rounded-full bg-sky-700 text-white transition hover:scale-105 hover:bg-sky-800"
          aria-label={isPlaying ? "Pausar música" : "Reproducir música"}
        >
          {isPlaying ? <Pause className="h-5 w-5" /> : <Play className="h-5 w-5" />}
        </button>
      </div>
    </div>
  );
}
