import type { Locale } from "@/data/invitation";
import { invitationContent } from "@/data/invitation";
import { SectionCard } from "@/components/ui/section-card";
import { buildWhatsAppLink } from "@/lib/whatsapp";
import { MessageCircleMore } from "lucide-react";

interface RSVPSectionProps {
  locale: Locale;
}

export function RSVPSection({ locale }: RSVPSectionProps) {
  const content = invitationContent[locale];
  const whatsappLink = buildWhatsAppLink(content.rsvp.phone, content.rsvp.message);

  return (
    <SectionCard title={content.rsvp.title}>
      <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div>
          <p className="text-lg font-semibold text-slate-800">{content.rsvp.heading}</p>
          <p className="mt-2 text-sm leading-7 text-slate-600">{content.rsvp.description}</p>
        </div>
        <a
          href={whatsappLink}
          target="_blank"
          rel="noreferrer"
          className="inline-flex items-center justify-center gap-2 rounded-full bg-sky-700 px-6 py-3 font-semibold text-white transition hover:bg-sky-800 hover:shadow-lg hover:shadow-sky-200"
        >
          <MessageCircleMore className="h-5 w-5" />
          {content.rsvp.button}
        </a>
      </div>
    </SectionCard>
  );
}
