const bears = Array.from({ length: 8 }, (_, index) => ({
  id: index,
  size: 44 + (index % 3) * 18,
  top: `${5 + index * 11}%`,
  left: `${index % 2 === 0 ? -1 : 78 + (index % 3) * 4}%`,
  delay: `${index * 0.7}s`
}));

export function BearBackground() {
  return (
    <div aria-hidden className="pointer-events-none absolute inset-0 overflow-hidden">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,rgba(191,219,254,0.55),transparent_34%),radial-gradient(circle_at_bottom_right,rgba(255,255,255,0.8),transparent_28%)]" />
      {bears.map((bear) => (
        <div
          key={bear.id}
          className="bear-float absolute rounded-full border border-sky-200/70 bg-amber-100/60 shadow-[0_10px_40px_rgba(148,163,184,0.18)]"
          style={{
            top: bear.top,
            left: bear.left,
            width: bear.size,
            height: bear.size,
            animationDelay: bear.delay
          }}
        >
          <span className="absolute -left-2 -top-2 h-4 w-4 rounded-full bg-amber-100/70" />
          <span className="absolute -right-2 -top-2 h-4 w-4 rounded-full bg-amber-100/70" />
          <span className="absolute bottom-2 left-1/2 h-3 w-3 -translate-x-1/2 rounded-full bg-slate-500/50" />
        </div>
      ))}
    </div>
  );
}
